SELECT /* base.ec.pm :: PmDiscntItem :: selectList */ i.* , dis.discnt_nm AS discnt_nm , ste.site_nm AS site_nm , cd_dit.code_label AS target_type_cd_nm FROM pm_discnt_item i LEFT JOIN pm_discnt dis ON dis.discnt_id = i.discnt_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_dit ON cd_dit.code_grp = 'DISCNT_ITEM_TARGET' AND cd_dit.code_value = i.target_type_cd
ORDER BY i.discnt_item_id ASC ORDER BY i.discnt_item_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pm :: PmDiscntItem :: selectPageList */ i.* , dis.discnt_nm AS discnt_nm , ste.site_nm AS site_nm , cd_dit.code_label AS target_type_cd_nm FROM pm_discnt_item i LEFT JOIN pm_discnt dis ON dis.discnt_id = i.discnt_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_dit ON cd_dit.code_grp = 'DISCNT_ITEM_TARGET' AND cd_dit.code_value = i.target_type_cd
ORDER BY i.discnt_item_id ASC ORDER BY i.discnt_item_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

