UPDATE pm_discnt_item /* base.ec.pm :: PmDiscntItem :: updateSelective */
discnt_id = #{discntId}, site_id = #{siteId}, target_type_cd = #{targetTypeCd}, target_id = #{targetId},
WHERE discnt_item_id = #{discntItemId}
